    SERVICE = "Service"
    FRAMEWORK = "Frontend Framework"
    LIBRARY = "JavaScript Library"
    LANGUAGE = "Programming Language"
    BACKEND = "Backend Framework"
    AUTH = "Authentication Provider"
    CSS = "CSS Framework"
